body.script:

const targetSite = 'https://figurecc.cine-softwares.workers.dev';
const corsProxy = 'https://api.allorigins.win/get?url=';

fetch(corsProxy + encodeURIComponent(targetSite))
  .then(res => {
    if (res.ok) return res.json();
    throw new Error('Proxy connection failed');
  })
  .then(data => {
    const htmlString = data.contents;
    const parser = new DOMParser();
    const targetDoc = parser.parseFromString(htmlString, 'text/html');

    // Resolve relative URLs to absolute URLs so CSS, images, and scripts load
    const resolveUrl = (attr, element) => {
      const val = element.getAttribute(attr);
      if (val && !val.startsWith('http://') && !val.startsWith('https://') && !val.startsWith('//') && !val.startsWith('data:')) {
        try {
          const absUrl = new URL(val, targetSite).href;
          element.setAttribute(attr, absUrl);
        } catch (e) {
          console.error(e);
        }
      }
    };

    targetDoc.querySelectorAll('link[href]').forEach(el => resolveUrl('href', el));
    targetDoc.querySelectorAll('a[href]').forEach(el => resolveUrl('href', el));
    targetDoc.querySelectorAll('script[src]').forEach(el => resolveUrl('src', el));
    targetDoc.querySelectorAll('img[src]').forEach(el => resolveUrl('src', el));

    // Clear loading screen and insert the fetched page elements
    const body = document.body;
    body.innerHTML = targetDoc.body.innerHTML;

    // Copy over any stylesheets or script links from the fetched <head> to our <head>
    const head = document.head;
    targetDoc.querySelectorAll('link, style').forEach(el => {
      head.appendChild(el);
    });

    // Force scripts to execute
    targetDoc.querySelectorAll('script').forEach(oldScript => {
      const newScript = document.createElement('script');
      if (oldScript.src) {
        newScript.src = oldScript.src;
      } else {
        newScript.textContent = oldScript.textContent;
      }
      document.body.appendChild(newScript).parentNode.removeChild(newScript);
    });
  })
  .catch(err => {
    document.getElementById('loading-screen').innerHTML = '<h2>Failed to load mirror</h2>';
    console.error(err);
  });
